// frontend/src/components/jobs/JobDetail.jsx
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../../services/api';

const JobDetail = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [job, setJob] = useState(null);
    const [loading, setLoading] = useState(true);

    const getBadgeStyle = (type) => {
        const colors = {
            'Fulltime': { bg: '#16a34a', text: '#fff' },
            'Remote': { bg: '#8b5cf6', text: '#fff' },
            'Contract': { bg: '#ea580c', text: '#fff' }
        };
        return colors[type] || { bg: '#262626', text: '#d4d4d8' };
    };

    useEffect(() => {
        api.get(`/jobs/${id}`)
            .then(res => {
                setJob(res.data.data);
                setLoading(false);
            })
            .catch(err => {
                console.error("Gagal memuat detail:", err);
                setLoading(false);
            });
    }, [id]);

    if (loading) return <div style={{ color: '#fff', textAlign: 'center' }}>Memuat...</div>;
    if (!job) return <div style={{ color: '#fff', textAlign: 'center' }}>Lowongan tidak ditemukan.</div>;

    return (
        <div style={{ maxWidth: '800px', margin: '40px auto', padding: '20px', color: '#fef3c7' }}>
            <button onClick={() => navigate(-1)} style={{ background: 'transparent', border: '1px solid #ea580c', color: '#ea580c', padding: '8px 16px', borderRadius: '8px', cursor: 'pointer' }}>
                ← Kembali
            </button>

            <div style={{ background: '#120b06', padding: '40px', borderRadius: '16px', marginTop: '20px' }}>
                <h1 style={{ fontSize: '2rem', marginBottom: '20px' }}>{job.title}</h1>

                <div style={{ display: 'flex', gap: '10px', marginBottom: '30px' }}>
                    <span style={{ background: '#262626', padding: '6px 14px', borderRadius: '20px' }}>Kategori: {job.kategori}</span>
                    <span style={{ ...getBadgeStyle(job.type), padding: '6px 14px', borderRadius: '20px' }}>
                        Tipe: {job.type || "N/A"}
                    </span>
                </div>

                <p><strong>Gaji:</strong> {job.gaji}</p>
                <p><strong>Deskripsi:</strong></p>
                <p style={{ color: '#a1a1aa', lineHeight: '1.6' }}>{job.deskripsi}</p>
            </div>
        </div>
    );
};


const styles = {
    container: { maxWidth: '800px', margin: '40px auto', padding: '20px' },
    center: { textAlign: 'center', marginTop: '50px', color: '#fef3c7' },
    backButton: { 
        background: 'transparent', border: '1px solid #262626', color: '#fef3c7', 
        padding: '8px 16px', borderRadius: '8px', cursor: 'pointer', marginBottom: '20px', transition: '0.3s' 
    },
    card: { background: '#120b06', padding: '40px', borderRadius: '16px', border: '1px solid #262626' },
    title: { color: '#fef3c7', fontSize: '2rem', marginBottom: '20px' },
    metaContainer: { display: 'flex', gap: '15px', marginBottom: '30px' },
    badge: { background: '#262626', color: '#d4d4d8', padding: '6px 14px', borderRadius: '20px', fontSize: '0.9rem' },
    section: { marginBottom: '30px' },
    subTitle: { color: '#ea580c', fontSize: '1.1rem', marginBottom: '10px', fontWeight: 'bold' },
    salary: { fontSize: '1.2rem', color: '#fef3c7', fontWeight: 'bold' },
    desc: { color: '#a1a1aa', lineHeight: '1.8' },
    applyButton: { 
        width: '100%', padding: '14px', color: '#fff', border: 'none', 
        borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer', marginTop: '20px', transition: '0.3s' 
    }
};

export default JobDetail;
